1	/**
2	 * Layerinfinite — api/index.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Main Hono application entry point.
5	 *
6	 * Middleware order:
7	 *   1. Global: logger, CORS, secureHeaders, prettyJSON
8	 *   2. Rate limit on all /v1 routes (tiered by customer tier)
9	 *   3. Admin routes: authMiddleware + adminAuthMiddleware
10	 *   4. Agent routes: authMiddleware (or devAuthMiddleware)
11	 *   5. validateActionMiddleware on log-outcome only
12	 * ══════════════════════════════════════════════════════════════
13	 */
14	
15	import 'dotenv/config';
16	
17	import { Hono } from 'hono';
18	import { cors } from 'hono/cors';
19	import { logger } from 'hono/logger';
20	import { secureHeaders } from 'hono/secure-headers';
21	import { prettyJSON } from 'hono/pretty-json';
22	import { serve } from '@hono/node-server';
23	import { getOutcomeQueueMode, startDurableQueueWorker, getDurableQueueHealth } from './lib/outcome-ingest-queue.js';
24	
25	const REQUIRED_ENV_VARS = [
26	    'SUPABASE_URL',
27	    'SUPABASE_SERVICE_ROLE_KEY',
28	    'SUPABASE_ANON_KEY',
29	];
30	
31	if (process.env.NODE_ENV === 'production') {
32	    REQUIRED_ENV_VARS.push('LAYERINFINITE_INTERNAL_SECRET');
33	}
34	
35	const missing = REQUIRED_ENV_VARS.filter(
36	    v => !process.env[v]
37	);
38	
39	if (missing.length > 0) {
40	    console.error(
41	        '❌ FATAL: Missing required environment variables:\n' +
42	        missing.map(v => `  - ${v}`).join('\n') +
43	        '\n\nCopy .env.example to .env and fill in values.\n' +
44	        'See PRODUCTION_CHECKLIST.md for instructions.'
45	    );
46	    process.exit(1);
47	}
48	
49	// In development, LAYERINFINITE_DEV_API_KEY is optional 
50	// (falls back to real auth). Never required in production.
51	if (process.env.NODE_ENV !== 'production' &&
52	    !process.env.LAYERINFINITE_DEV_API_KEY) {
53	    console.warn(
54	        '⚠️  LAYERINFINITE_DEV_API_KEY not set. ' +
55	        'Dev bypass will require real API keys. ' +
56	        'Set it in .env for local testing convenience.'
57	    );
58	}
59	
60	import { authMiddleware, devAuthMiddleware } from './middleware/auth.js';
61	import { adminAuthMiddleware } from './middleware/admin-auth.js';
62	import { rateLimitMiddleware } from './middleware/rate-limit.js';
63	import { validateActionMiddleware } from './middleware/validate-action.js';
64	
65	import { logOutcomeRouter } from './routes/log-outcome.js';
66	import { getScoresRouter } from './routes/get-scores.js';
67	import { getPatternsRouter } from './routes/get-patterns.js';
68	import { auditRouter } from './routes/audit.js';
69	import { actionsRouter } from './routes/admin/actions.js';
70	import { reinstateAgentRouter } from './routes/admin/reinstate-agent.js';
71	import { reinstateSandboxRouter } from './routes/admin/reinstate-sandbox.js';
72	import { testNotificationRouter } from './routes/admin/test-notification.js';
73	import { triggerTrainingRoute } from './routes/admin/trigger-training.js';
74	import { restoreTrustSnapshotRouter } from './routes/admin/restore-trust-snapshot.js';
75	import { embeddingDriftRouter } from './routes/admin/embedding-drift.js';
76	import { userAuthMiddleware } from './middleware/user-auth.js';
77	import { apiKeysRouter } from './routes/auth/api-keys.js';
78	import { meRouter } from './routes/auth/me.js';
79	import { outcomeFeedbackRouter } from './routes/outcome-feedback.js';
80	import { simulateRouter } from './routes/simulate.js';
81	import contractsRoute from './routes/contracts.js';
82	import discrepancyRoute from './routes/discrepancy.js';
83	import pendingSignalsRoute from './routes/pending-signals.js';
84	import webhookRoute from './routes/webhook.js';
85	import { getRecommendationsRouter } from './routes/get-recommendations.js';
86	import { observeRouter } from './routes/observe.js';
87	import { importRouter } from './routes/import.js';
88	
89	// ── PORT: Railway injects PORT, fallback to API_PORT, then 3000 ──
90	const PORT = parseInt(process.env.PORT ?? process.env.API_PORT ?? '3000', 10);
91	
92	// ── FATAL: Dev bypass CANNOT be active in production ──────────
93	if (process.env.NODE_ENV === 'production' &&
94	    process.env.LAYERINFINITE_DEV_BYPASS === 'true') {
95	    console.error('FATAL: Dev bypass cannot be active in production. Set LAYERINFINITE_DEV_BYPASS=false.');
96	    process.exit(1);
97	}
98	
99	// ── Create app ────────────────────────────────────────────────
100	const app = new Hono();
101	
102	// ── CORS: env-driven origins ──────────────────────────────────
103	const allowedOrigins = process.env.ALLOWED_ORIGINS
104	    ? process.env.ALLOWED_ORIGINS.split(',').map(o => o.trim()).filter(Boolean)
105	    : ['http://localhost:3000', 'http://localhost:5173'];
106	
107	// Warn loudly in production if no https:// origin is configured
108	if (process.env.NODE_ENV === 'production') {
109	    const hasHttps = allowedOrigins.some(o => o.startsWith('https://'));
110	    if (!hasHttps) {
111	        console.warn(
112	            '⚠️  CORS WARNING: ALLOWED_ORIGINS contains no https:// URL in production.\n' +
113	            '   Current origins: ' + allowedOrigins.join(', ') + '\n' +
114	            '   All browser requests from your dashboard will be blocked.\n' +
115	            '   Set ALLOWED_ORIGINS=https://your-dashboard.vercel.app on Railway.'
116	        );
117	    }
118	}
119	
120	// ── Global middleware ─────────────────────────────────────────
121	app.use('*', logger());
122	app.use('*', secureHeaders());
123	app.use('*', cors({
124	    origin: (origin) => allowedOrigins.includes(origin) ? origin : null,
125	    allowHeaders: ['X-API-Key', 'X-Admin-Key', 'Authorization', 'Content-Type'],
126	    allowMethods: ['GET', 'POST', 'PUT', 'DELETE', 'OPTIONS'],
127	    exposeHeaders: ['X-RateLimit-Limit', 'X-RateLimit-Remaining', 'X-RateLimit-Reset'],
128	}));
129	app.use('*', prettyJSON());
130	
131	// ── Global Timeout Middleware ─────────────────────────────────
132	const REQUEST_TIMEOUT_MS = parseInt(process.env.REQUEST_TIMEOUT_MS ?? '10000', 10);
133	
134	app.use('*', async (c, next) => {
135	    if (
136	        c.req.path === '/health' ||
137	        c.req.path === '/health/deep' ||
138	        c.req.path === '/'
139	    ) {
140	        return next();
141	    }
142	
143	    const controller = new AbortController();
144	    let timeoutId: ReturnType<typeof setTimeout> | null = null;
145	
146	    const timeoutPromise = new Promise<never>((_, reject) => {
147	        const onAbort = () => reject(new Error('TIMEOUT'));
148	        controller.signal.addEventListener('abort', onAbort, { once: true });
149	        // { once: true } automatically removes the listener after it fires.
150	        // This prevents listener accumulation on the happy path.
151	    });
152	
153	    timeoutId = setTimeout(
154	        () => controller.abort(),
155	        REQUEST_TIMEOUT_MS
156	    );
157	
158	    const start = Date.now();
159	
160	    try {
161	        await Promise.race([next(), timeoutPromise]);
162	    } catch (e: any) {
163	        if (e?.message === 'TIMEOUT') {
164	            const elapsed = Date.now() - start;
165	            console.warn(
166	                `[layerinfinite] Request timeout on ${c.req.path} ` +
167	                `after ${elapsed}ms`
168	            );
169	            return c.json(
170	                {
171	                    error: 'Request timeout',
172	                    code: 'GATEWAY_TIMEOUT',
173	                    timeout_ms: REQUEST_TIMEOUT_MS,
174	                },
175	                504
176	            );
177	        }
178	        throw e;
179	    } finally {
180	        if (timeoutId !== null) clearTimeout(timeoutId);
181	        // AbortController itself is GC'd after this scope ends.
182	        // No manual cleanup needed — { once: true } handles listener removal.
183	    }
184	});
185	
186	// ── Health check (no auth, no rate limiting) ──────────────────
187	app.get('/', (c) => c.json({
188	    service: 'Layerinfinite Decision Intelligence API',
189	    version: '1.0.0',
190	    status: 'healthy',
191	    timestamp: new Date().toISOString(),
192	    cors: {
193	        origins_count: allowedOrigins.length,
194	        has_production_origin: allowedOrigins.some(o => o.startsWith('https://')),
195	    },
196	    endpoints: {
197	        'POST /v1/log-outcome': 'Append outcome to fact_outcomes',
198	        'GET  /v1/get-scores': 'Get ranked action scores',
199	        'GET  /v1/get-patterns': 'Get action sequence patterns',
200	        'GET  /v1/recommendations': 'Get decision recommendation for a task',
201	        'GET  /v1/observe': 'Get per-task outcome statistics (total runs, success rate, best/worst action)',
202	        'GET  /v1/contracts': 'Signal contracts',
203	        'GET  /v1/discrepancies': 'Signal discrepancies',
204	        'GET  /v1/pending-signals': 'Pending signal queue',
205	        'POST /v1/webhook/:provider': 'Webhook ingestion',
206	        'GET /v1/me': 'Verify API key identity — returns agent_id + customer_id',
207	        'GET  /v1/audit': 'Immutable audit trail',
208	        'POST /v1/admin/register-action': 'Register an action (admin)',
209	        'GET  /v1/admin/actions': 'List actions (admin)',
210	        'POST /v1/admin/reinstate-agent': 'Reinstate suspended agent (admin)',
211	        'POST /v1/admin/test-notification': 'Test a notification channel (admin)',
212	        'GET  /health/deep': 'Deep health check (table + env var diagnostics)',
213	    },
214	}));
215	
216	app.get('/health', async (c) => {
217	    const checks: Record<string, string> = { api: 'ok' };
218	    let overallStatus = 'ok';
219	
220	    try {
221	        const { supabase } = await import('./lib/supabase.js');
222	        const { error } = await supabase.from('dim_customers').select('customer_id').limit(1);
223	        checks.database = error ? 'error' : 'ok';
224	    } catch {
225	        checks.database = 'error';
226	    }
227	
228	    try {
229	        const { supabase } = await import('./lib/supabase.js');
230	        const { data, error } = await supabase
231	            .from('mv_action_scores')
232	            .select('view_refreshed_at')
233	            .limit(1);
234	
235	        if (error || !data || data.length === 0) {
236	            checks.materialized_view = 'stale';
237	        } else {
238	            const refreshedAt = new Date(data[0].view_refreshed_at);
239	            const ageMinutes = (Date.now() - refreshedAt.getTime()) / 60000;
240	            checks.materialized_view = ageMinutes > 15 ? 'stale' : 'ok';
241	        }
242	    } catch {
243	        checks.materialized_view = 'error';
244	    }
245	
246	    try {
247	        const { supabase } = await import('./lib/supabase.js');
248	        const { error: tapErr } = await supabase
249	            .from('mv_task_action_performance_180d')
250	            .select('customer_id')
251	            .limit(1);
252	        checks.mv_task_action_performance_180d = tapErr
253	            ? `error: ${tapErr.message}`
254	            : 'ok';
255	    } catch {
256	        checks.mv_task_action_performance_180d = 'error';
257	    }
258	
259	    if (Object.values(checks).some(v => v === 'error' || v.startsWith('error'))) {
260	        overallStatus = 'degraded';
261	    } else if (Object.values(checks).some(v => v === 'stale')) {
262	        overallStatus = 'degraded';
263	    }
264	
265	    return c.json({
266	        status: overallStatus,
267	        timestamp: new Date().toISOString(),
268	        checks,
269	        version: '1.0.0',
270	    });
271	});
272	
273	// ── Deep health check ───────────────────────────────────────
274	app.get('/health/deep', async (c) => {
275	    const checks: Record<string, string> = { api: 'ok' };
276	    let overallStatus = 'ok';
277	
278	    // ── Table reachability checks ──────────────────────────
279	    const tables = ['dim_agents', 'dim_customers', 'user_profiles', 'dim_actions', 'dim_contexts'] as const;
280	    try {
281	        const { supabase } = await import('./lib/supabase.js');
282	        for (const table of tables) {
283	            try {
284	                const { error } = await (supabase as any).from(table).select('*').limit(1);
285	                checks[`table_${table}`] = error ? `error: ${error.message}` : 'ok';
286	            } catch (e: any) {
287	                checks[`table_${table}`] = `error: ${e.message}`;
288	            }
289	        }
290	    } catch (e: any) {
291	        for (const table of tables) checks[`table_${table}`] = 'error: supabase unavailable';
292	    }
293	
294	    // ── Schema version ─────────────────────────────────────
295	    try {
296	        const { supabase } = await import('./lib/supabase.js');
297	        const { data, error } = await supabase
298	            .from('schema_migrations')
299	            .select('version')
300	            .order('version', { ascending: false })
301	            .limit(1);
302	        checks.schema_version = (!error && data && data.length > 0)
303	            ? `v${data[0].version}`
304	            : 'unknown';
305	    } catch {
306	        checks.schema_version = 'unknown';
307	    }
308	
309	    // ── Environment variable checks ────────────────────────
310	    checks.env_ALLOWED_ORIGINS = process.env.ALLOWED_ORIGINS
311	        ? `set (${allowedOrigins.length} origins)`
312	        : 'missing';
313	    checks.env_LAYERINFINITE_INTERNAL_SECRET = process.env.LAYERINFINITE_INTERNAL_SECRET
314	        ? 'set'
315	        : 'missing';
316	    checks.env_SUPABASE_URL = process.env.SUPABASE_URL ? 'set' : 'missing';
317	    checks.env_SUPABASE_SERVICE_ROLE_KEY = process.env.SUPABASE_SERVICE_ROLE_KEY ? 'set' : 'missing';
318	
319	    // ── Existing materialized view check ──────────────────
320	    try {
321	        const { supabase } = await import('./lib/supabase.js');
322	        const { data, error } = await supabase
323	            .from('mv_action_scores')
324	            .select('view_refreshed_at')
325	            .limit(1);
326	        if (error || !data || data.length === 0) {
327	            checks.materialized_view = 'stale';
328	        } else {
329	            const ageMinutes = (Date.now() - new Date(data[0].view_refreshed_at).getTime()) / 60000;
330	            checks.materialized_view = ageMinutes > 15 ? 'stale' : 'ok';
331	        }
332	    } catch {
333	        checks.materialized_view = 'error';
334	    }
335	
336	    try {
337	        const { supabase } = await import('./lib/supabase.js');
338	        const { error: tapErr } = await supabase
339	            .from('mv_task_action_performance_180d')
340	            .select('customer_id')
341	            .limit(1);
342	        checks.mv_task_action_performance_180d = tapErr
343	            ? `error: ${tapErr.message}`
344	            : 'ok';
345	    } catch {
346	        checks.mv_task_action_performance_180d = 'error';
347	    }
348	
349	    // ── mv_episode_patterns: regression guard ──────────────
350	    // Catches if the MV is rebuilt against the wrong source table (bug from migration 064).
351	    // Only warns if fact_outcomes already has episode rows — fresh deploys are fine at 0.
352	    try {
353	        const { supabase } = await import('./lib/supabase.js');
354	        const { count: outcomeCount } = await supabase
355	            .from('fact_outcomes')
356	            .select('*', { count: 'exact', head: true })
357	            .not('episode_id', 'is', null);
358	        const { count: patternCount, error: mvErr } = await supabase
359	            .from('mv_episode_patterns')
360	            .select('*', { count: 'exact', head: true });
361	        if (mvErr) {
362	            checks.mv_episode_patterns = `error: ${mvErr.message}`;
363	        } else if ((outcomeCount ?? 0) > 5 && (patternCount ?? 0) === 0) {
364	            checks.mv_episode_patterns = 'warn: 0 patterns but outcomes exist — run refresh_mv_episode_patterns()';
365	        } else {
366	            checks.mv_episode_patterns = `ok (${patternCount ?? 0} patterns)`;
367	        }
368	    } catch {
369	        checks.mv_episode_patterns = 'error';
370	    }
371	
372	    // ── Schema invariants (via DB function) ────────────────
373	    // verify_schema_invariants() is defined in migration 065.
374	    // Checks: action_sequences FK absent, event_type values valid.
375	    try {
376	        const { supabase } = await import('./lib/supabase.js');
377	        const { data, error } = await supabase.rpc('verify_schema_invariants' as any);
378	        if (error) {
379	            checks.schema_invariants = 'unknown (function not found — run migration 065)';
380	        } else {
381	            const result = data as { pass: boolean; failures: string[] };
382	            checks.schema_invariants = result.pass
383	                ? 'ok'
384	                : `FAIL: ${result.failures.join(', ')}`;
385	        }
386	    } catch {
387	        checks.schema_invariants = 'unknown';
388	    }
389	
390	    // ── Durable queue health ───────────────────────────────
391	    const currentQueueMode = getOutcomeQueueMode();
392	    checks.queue_mode = currentQueueMode;
393	    if (currentQueueMode === 'postgres') {
394	        try {
395	            const queueHealth = await getDurableQueueHealth();
396	            checks.queue_pending = String(queueHealth.pending);
397	            checks.queue_failed = String(queueHealth.failed);
398	            checks.queue_dead = String(queueHealth.dead);
399	            checks.queue_processing = String(queueHealth.processing);
400	            checks.queue_oldest_pending_age_seconds = queueHealth.oldest_pending_age_seconds !== null
401	                ? `${queueHealth.oldest_pending_age_seconds}s`
402	                : 'none';
403	            if (queueHealth.dead > 0) {
404	                checks.queue_dead_letter_warning = `warn: ${queueHealth.dead} dead-lettered items — inspect queue_outcome_ingress WHERE status='dead'`;
405	            }
406	        } catch {
407	            checks.queue_health = 'error: unable to query queue table';
408	        }
409	    }
410	
411	    // ── Overall status calculation ─────────────────────────
412	    const vals = Object.values(checks);
413	    if (vals.some(v =>
414	        v.startsWith('error') ||
415	        v === 'missing' ||
416	        v.startsWith('FAIL')
417	    )) {
418	        overallStatus = 'degraded';
419	    } else if (vals.some(v =>
420	        v === 'stale' ||
421	        v === 'unknown' ||
422	        v.startsWith('warn:')
423	    )) {
424	        overallStatus = 'warn';
425	    }
426	
427	    return c.json({
428	        status: overallStatus,
429	        timestamp: new Date().toISOString(),
430	        checks,
431	        version: '1.0.0',
432	    }, overallStatus === 'ok' ? 200 : 503);
433	});
434	
435	// ── Internal: scoring cache refresh ───────────────────────────
436	app.post('/internal/refresh-score-cache', async (c) => {
437	    const auth = c.req.header('Authorization');
438	    const internalSecret = process.env.LAYERINFINITE_INTERNAL_SECRET;
439	    if (!internalSecret || auth !== `Bearer ${internalSecret}`) {
440	        return c.json({ error: 'Unauthorized' }, 401);
441	    }
442	    const { invalidateCache } = await import('./lib/scoring.js');
443	    // clears entire in-memory score cache
444	    invalidateCache();
445	    return c.json({ ok: true, message: 'Score cache cleared' });
446	});
447	
448	// ── v1 API ────────────────────────────────────────────────────
449	const v1 = new Hono();
450	
451	const primaryAuth = process.env.NODE_ENV === 'production'
452	    ? authMiddleware
453	    : devAuthMiddleware;
454	
455	const authRoutes = new Hono();
456	authRoutes.use('*', userAuthMiddleware);
457	authRoutes.route('/api-keys', apiKeysRouter);
458	authRoutes.route('/keys', apiKeysRouter);
459	v1.route('/auth', authRoutes);
460	
461	v1.use('/me', primaryAuth);
462	v1.route('/me', meRouter);
463	
464	v1.use('/admin/*', primaryAuth, adminAuthMiddleware);
465	v1.route('/admin', actionsRouter);
466	v1.route('/admin/reinstate-agent', reinstateAgentRouter);
467	v1.route('/admin', reinstateSandboxRouter);
468	v1.route('/admin/test-notification', testNotificationRouter);
469	v1.route('/admin/trigger-training', triggerTrainingRoute);
470	v1.route('/admin/restore-trust-snapshot', restoreTrustSnapshotRouter);
471	v1.route('/admin/embedding-drift', embeddingDriftRouter);
472	
473	v1.use('/outcome-feedback', primaryAuth);
474	v1.use('/outcome-feedback/*', primaryAuth);
475	v1.use('/recommendations', primaryAuth);
476	v1.use('/recommendations/*', primaryAuth);
477	v1.use('/observe', primaryAuth);
478	v1.use('/observe/*', primaryAuth);
479	v1.use('/get-patterns', primaryAuth);
480	v1.use('/get-patterns/*', primaryAuth);
481	v1.use('/audit', primaryAuth);
482	v1.use('/audit/*', primaryAuth);
483	v1.use('/simulate', primaryAuth);
484	v1.use('/simulate/*', primaryAuth);
485	v1.use('/contracts', primaryAuth);
486	v1.use('/contracts/*', primaryAuth);
487	v1.use('/discrepancies', primaryAuth);
488	v1.use('/discrepancies/*', primaryAuth);
489	v1.use('/pending-signals', primaryAuth);
490	v1.use('/pending-signals/*', primaryAuth);
491	v1.use('/import', primaryAuth);
492	v1.use('/import/*', primaryAuth);
493	
494	// Apply route-specific rate limiting only after auth has set customer_id.
495	app.use('/v1/log-outcome', primaryAuth, rateLimitMiddleware, validateActionMiddleware);
496	app.use('/v1/log-outcome/*', primaryAuth, rateLimitMiddleware, validateActionMiddleware);
497	app.use('/v1/get-scores', primaryAuth, rateLimitMiddleware);
498	app.use('/v1/get-scores/*', primaryAuth, rateLimitMiddleware);
499	
500	v1.route('/log-outcome', logOutcomeRouter);
501	v1.route('/outcome-feedback', outcomeFeedbackRouter);
502	v1.route('/get-scores', getScoresRouter);
503	v1.route('/recommendations', getRecommendationsRouter);
504	v1.route('/observe', observeRouter);
505	v1.route('/get-patterns', getPatternsRouter);
506	v1.route('/audit', auditRouter);
507	v1.route('/simulate', simulateRouter);
508	v1.route('/contracts', contractsRoute);
509	v1.route('/discrepancies', discrepancyRoute);
510	v1.route('/pending-signals', pendingSignalsRoute);
511	v1.route('/import', importRouter);
512	v1.post('/webhook/:provider', webhookRoute);
513	
514	app.route('/v1', v1);
515	
516	// ── 404 fallback ──────────────────────────────────────────────
517	app.notFound((c) => c.json(
518	    { error: 'Route not found', code: 'NOT_FOUND', available_prefix: '/v1' },
519	    404
520	));
521	
522	// ── Global error handler ──────────────────────────────────────
523	app.onError((err, c) => {
524	    console.error('[layerinfinite] Unhandled error:', err.message);
525	    const isProduction = process.env.NODE_ENV === 'production';
526	    return c.json(
527	        {
528	            error: 'Internal server error',
529	            code: 'INTERNAL_ERROR',
530	            ...(isProduction ? {} : { message: err.message }),
531	        },
532	        500
533	    );
534	});
535	
536	// ── Start server ──────────────────────────────────────────────
537	serve({
538	    fetch: app.fetch,
539	    port: PORT,
540	}, (info) => {
541	    console.log(`\n🚀 Layerinfinite API running on port ${info.port}`);
542	    console.log(`   Mode:       ${process.env.NODE_ENV ?? 'development'}`);
