1	/**
2	 * LayerInfinite MCP Server — tools/li-log.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * FOUNDATION TOOL — Always registered, works from Day 0.
5	 *
6	 * Logs the outcome of an action the agent just performed.
7	 * Maps to POST /v1/log-outcome on the LI REST API.
8	 *
9	 * decision_id is ALWAYS optional:
10	 *   - Bootstrap (no mode): agent just logs, no prior li_action call
11	 *   - Recommend: optional linkage if agent read the resource
12	 *   - Assist/Auto: set by li_action gateway, passed through here
13	 * ══════════════════════════════════════════════════════════════
14	 */
15	
16	import { z } from 'zod';
17	import { randomUUID } from 'node:crypto';
18	import type { RestClient } from '../rest-client.js';
19	
20	export const LI_LOG_NAME = 'li_log';
21	
22	export const LI_LOG_DESCRIPTION =
23	  'Log the outcome of an action you just performed. Call this EVERY TIME you ' +
24	  'complete a task action, regardless of mode. This is how LayerInfinite learns ' +
25	  'which actions work best for each task.';
26	
27	export const liLogSchema = {
28	  task: z.string().min(1).describe('Task name, e.g. "payment_failed", "refund_request"'),
29	  action_taken: z.string().min(1).describe('The action that was executed'),
30	  success: z.boolean().describe('Whether the action succeeded'),
31	  error_code: z.string().optional().describe('Error code if the action failed'),
32	  error_message: z.string().max(500).optional().describe('Brief error description'),
33	  outcome_score: z.number().min(0).max(1).optional().describe('Granular outcome score 0.0-1.0'),
34	  business_outcome: z.enum(['resolved', 'partial', 'failed', 'unknown']).optional().describe('Business-level result'),
35	  response_time_ms: z.number().int().min(0).optional().describe('How long the action took in ms'),
36	  decision_id: z.string().uuid().optional().describe('From li_action if called prior — links outcome to decision'),
37	  episode_id: z.string().uuid().optional().describe('Groups related actions in a multi-step sequence'),
38	  redirected_from: z.string().optional().describe('Original action name if auto-redirected by li_action'),
39	};
40	
41	export type LiLogInput = z.infer<z.ZodObject<typeof liLogSchema>>;
42	
43	/** Response shape from POST /v1/log-outcome. */
44	interface LogOutcomeResponse {
45	  outcome_id?: string;
46	  status?: string;
47	  data_quality_score?: number;
48	  [key: string]: unknown;
49	}
50	
51	/** Response shape from GET /v1/observe (used to get task stats). */
52	interface ObserveResponse {
53	  total_runs?: number;
54	  [key: string]: unknown;
55	}
56	
57	export function createLiLogHandler(client: RestClient) {
58	  return async (input: LiLogInput) => {
59	    // ── Build the log-outcome payload ───────────────────────
60	    const payload: Record<string, unknown> = {
61	      action_name: input.action_taken,
62	      issue_type: input.task,
63	      success: input.success,
64	      session_id: randomUUID(),
65	      idempotency_key: randomUUID(),
66	      ingestion_source: 'mcp',
67	    };
68	
69	    // Optional fields — only set if provided
70	    if (input.error_code) payload.error_code = input.error_code;
71	    if (input.error_message) payload.error_message = input.error_message;
72	    if (input.outcome_score !== undefined) payload.outcome_score = input.outcome_score;
73	    if (input.business_outcome) payload.business_outcome = input.business_outcome;
74	    if (input.response_time_ms !== undefined) payload.response_time_ms = input.response_time_ms;
75	    if (input.decision_id) payload.decision_id = input.decision_id;
76	    if (input.episode_id) payload.episode_id = input.episode_id;
77	
78	    // Redirect audit trail (Gap Fix #3)
79	    if (input.redirected_from) {
80	      payload.metadata = { redirected_from: input.redirected_from };
81	    }
82	
83	    // ── POST /v1/log-outcome ────────────────────────────────
84	    const result = await client.post<LogOutcomeResponse>('/v1/log-outcome', payload);
85	
86	    if (!result.ok) {
87	      return {
88	        content: [{
89	          type: 'text' as const,
90	          text: JSON.stringify({
91	            logged: false,
92	            error: result.error.message ?? result.error.error,
93	            code: result.error.code,
94	          }),
95	        }],
96	        isError: true,
97	      };
98	    }
99	
100	    // ── Fetch task stats for progress feedback ──────────────
101	    // Non-critical: if this fails, we still return success
102	    let outcomesForTask = 0;
103	    let recommendationsAvailable = false;
104	    const STABLE_THRESHOLD = 50;
105	
106	    try {
107	      const statsResult = await client.get<ObserveResponse>('/v1/observe', {
108	        task: input.task,
109	      });
110	      if (statsResult.ok && statsResult.data.total_runs !== undefined) {
111	        outcomesForTask = statsResult.data.total_runs;
112	        recommendationsAvailable = outcomesForTask >= STABLE_THRESHOLD;
113	      }
114	    } catch {
115	      // Stats fetch is best-effort — don't fail the log
116	    }
117	
118	    const outcomesNeeded = Math.max(0, STABLE_THRESHOLD - outcomesForTask);
119	
120	    return {
121	      content: [{
122	        type: 'text' as const,
123	        text: JSON.stringify({
124	          logged: true,
125	          outcome_id: result.data.outcome_id ?? null,
126	          data_quality_score: result.data.data_quality_score ?? null,
127	          outcomes_for_task: outcomesForTask,
128	          recommendations_available: recommendationsAvailable,
129	          outcomes_needed: outcomesNeeded,
130	          ...(input.redirected_from ? { redirected_from: input.redirected_from } : {}),
131	        }),
132	      }],
133	    };
134	  };
135	}
