626	        .eq('action_id', outcome.action_id)
627	        .eq('alert_type', 'degradation')
628	        .gte('detected_at', since24h)
629	        .limit(1);
630	
631	    if (recentAlert && recentAlert.length > 0) return;
632	
633	    await sb.from('degradation_alert_events').insert({
634	        customer_id: outcome.customer_id,
635	        action_id: outcome.action_id,
636	        alert_type: 'degradation',
637	        severity: 'warning',
638	        current_value: outcome.outcome_score,
639	        baseline_value: 1.0,
640	        message: `Silent failure detected on "${outcome.action_name}": success=true but outcome_score=${outcome.outcome_score}. Technical success, business failure. Score will reflect true outcome.`,
