779	async function insertCoreOutcome(
780	    agentId: string, customerId: string, actionId: string, contextId: string,
781	    body: any, finalSuccess: boolean, finalOutcomeScore: number | null, verification: any,
782	    executionStatus: ExecutionStatus,
783	    failureReasonCode: string | null,
784	    failureStage: string | null,
785	    statusOrigin: StatusOrigin,
786	    outcomeScoreRaw: number | null,
787	    dataQuality: number,
788	    isInconsistent: boolean,
789	    inconsistencyType: string | null,
790	    inconsistencyReason: string | null,
791	    mappingConfidence: number,
792	    scoreOrigin: 'provided' | 'inferred',
793	    mappingTier: string,
794	    inconsistencyRuleVersion: string | null,
795	    semanticCluster: SemanticActionClusterResult,
796	    crossEventStatus: 'none' | 'pending_signal' | 'confirmed' | 'conflict' | 'resolved',
797	    retryChain: RetryChainState,
798	    inferenceConfidence: number | null,
799	    outcomeClass: string | null,
800	) {
801	    // RULE: backprop_episode_id is INTERNAL — set by the backprop engine only.
802	    // NEVER map body.episode_id to this column. body.episode_id is the SDK's
803	    // sequence-tracking field; backprop_episode_id has a FK to fact_episodes which
804	    // only the backprop engine populates. Passing body.episode_id here causes FK
805	    // violation 23503 on every request that sends episode_id.
806	    const inserted = await insertOutcomeRecord({
807	        agent_id: agentId,
808	        action_id: actionId,
809	        context_id: contextId,
810	        customer_id: customerId,
811	        session_id: body.session_id,
812	        success: finalSuccess,
813	        response_time_ms: body.response_time_ms ?? null,
814	        error_code: body.error_code ?? null,
815	        error_message: body.error_message ?? null,
816	        raw_context: body.raw_context ?? {},
817	        is_synthetic: false,
818	        // All SDK-originated rows are explicitly marked 'sdk'.
819	        // Import rows written by the import route use 'import'.
820	        // Trust-update paths filter on this column to exclude imported history.
821	        ingestion_source: 'sdk',
822	        salience_score: computeSalience(actionId, contextId, customerId, finalSuccess),
823	        // outcome_score is NOT NULL in DB (migration 044 adds constraint + DEFAULT 0.5).
824	        // After inference engine (migration 102), finalOutcomeScore includes inferred
825	        // values when developer omits score_fn. The ?? 0.5 fallback is a last resort
826	        // if inference also failed (should never happen — defense in depth).
827	        // Raw developer signal preserved in outcome_score_raw.
828	        outcome_score: finalOutcomeScore ?? 0.5,
829	        business_outcome: body.business_outcome ?? null,
830	        feedback_signal: body.feedback_signal ?? 'immediate',
831	        verifier_source: body.verifier_signal?.source ?? null,
832	        verifier_value: body.verifier_signal?.value?.toString() ?? null,
833	        discrepancy_detected: verification.discrepancy_detected,
834	        backprop_episode_id: body.backprop_episode_id ?? null,
835	        // episode_id: the SDK's sequence-grouping field.
836	        // Stored as plain UUID string — no FK constraint.
837	        // Distinct from backprop_episode_id which has a FK to fact_episodes.
838	        episode_id: body.episode_id ?? null,
839	        // ── Phase 1: Signal columns ───────────────────────
840	        signal_source: body.signal_source ?? 'explicit',
841	        signal_confidence: body.causal_confidence ?? null,
842	        causal_depth: body.signal_depth ?? null,
843	        signal_pending: crossEventStatus === 'pending_signal',
844	        signal_updated_at: null,
845	        cross_event_status: crossEventStatus,
846	        cross_event_last_updated: new Date().toISOString(),
847	        retry_chain_id: retryChain.retryChainId,
848	        retry_attempt: retryChain.retryAttempt,
849	        cross_event_attempt_count: retryChain.crossEventAttemptCount,
850	        canonical_outcome_id: retryChain.canonicalOutcomeId,
851	        pending_registration_id: null,
852	        execution_status: executionStatus,
