1479	
1480	    } catch (err: any) {
1481	        if (err.message === 'PAYLOAD_TOO_LARGE') {
1482	            return c.json({ error: 'PAYLOAD_TOO_LARGE', message: 'raw_context exceeds 64KB limit' }, 413);
1483	        }
1484	        if (err.message === 'CONFLICT') {
1485	            return c.json({ error: 'Duplicate idempotency_key — this outcome was already logged. Pass the same key to retrieve the original outcome_id.', code: 'CONFLICT' }, 409);
1486	        }
1487	        if (err.message === 'DECISION_AGENT_MISMATCH') {
1488	            return c.json({ error: 'decision_id belongs to a different agent', code: 'DECISION_AGENT_MISMATCH' }, 400);
1489	        }
1490	        if (err.message.startsWith('STATUS_CONFLICT:')) {
1491	            return c.json({
1492	                error: 'execution_status conflicts with resolved success',
1493	                details: err.message.substring(16),
1494	                code: 'STATUS_CONFLICT',
1495	            }, 400);
1496	        }
1497	        if (err.message.startsWith('UNKNOWN_ACTION:')) {
1498	            const parts = err.message.split(':');
1499	            return c.json({ error: parts[1], message: parts[2] }, 400);
1500	        }
1501	        if (err.message.startsWith('VALIDATION_ERROR:')) {
1502	            return c.json({ error: 'Invalid request body', details: err.message.substring(17), code: 'VALIDATION_ERROR' }, 400);
1503	        }
1504	        if (err.message.startsWith('CONTEXT_ERROR:')) {
1505	            return c.json({ error: 'Failed to resolve context', details: err.message.substring(14), code: 'CONTEXT_ERROR' }, 500);
1506	        }
1507	        if (err.message.startsWith('INSERT_ERROR:')) {
1508	            return c.json({ error: 'Failed to log outcome', details: err.message.substring(13), code: 'INSERT_ERROR' }, 500);
1509	        }
1510	        return c.json({ error: 'Internal server error', details: err.message }, 500);
1511	    }
1512	});
